window.__QUIZ_DATA__=[{"id":"objective>Agricultural Science>2016>1","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"BASIC CONCEPTS : PROBLEMS OF AGRICULTURAL DEVELOPMENT AND POSSIBLE SOLUTIONS","question":"Which of the following suggestions would solve transportation problems associated with agriculture?","images":[],"options":{"A":"Establishment of tractor hiring units","B":"Efficient railway system","C":"Establishment of far hire units","D":"Provision of extension services"},"answer":"B","explanation":"Efficient railway system would solve transportation problems associated with agriculture. This will enhance the easy distribution of agricultural product over a far distance","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>2","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"BASIC CONCEPTS : MEANING AND IMPORTANCE OF AGRICULTURE","question":"Which of the following statements is not correct about agriculture in most West Africa countries? It provides","images":[],"options":{"A":"employment","B":"fuel","C":"food","D":"income"},"answer":"B","explanation":"Agriculture in most West African countries provides   - employment - food - income - country capital etc   Fuel is provided by Agriculture","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>3","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : LAND AND ITS USE","question":"The document given to a farmer on acquiring a piece of land from government is called","images":[],"options":{"A":"certificate of purchase","B":"receipt of ownership","C":"certificate of occupancy","D":"receipt of lease"},"answer":"C","explanation":"Certificate of occupancy (C of O) is the document given to a farmer on acquiring of a piece of land from government","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>4","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The diagram below shows some parts of a plough. Study it and answer questions below    The part labelled I in the diagram is the","images":["data:image/png;base64,"],"options":{"A":"hitch","B":"handle","C":"plough share","D":"mouldboard"},"answer":"D","explanation":"The part labelled I is the mouldboard   The mouldboard is a key component of a plough, specifically designed to turn over the soil. In farming equipment:    Function: The mouldboard lifts and turns the soil over after it's cut by the ploughshare. This action helps bury crop residues and weeds, improving soil aeration and preparing the seedbed.    Location: It's typically the curved part of the plough attached behind the ploughshare, which slices the soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>5","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The part labelled II is the","images":["data:image/png;base64,"],"options":{"A":"wheel","B":"plough share","C":"handle","D":"mouldboard"},"answer":"B","explanation":"The part labelled II is the plough share   The ploughshare is an essential part of a plough, here's its role:    Function: The ploughshare is the cutting edge of the plough that slices through the soil horizontally. It works together with the mouldboard to cut, lift, and turn the soil during ploughing.    Location: Positioned at the bottom of the plough, it is located in front of the mouldboard and directly engages the soil.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>6","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"Which of the following functions is not associated with the part labelled I?","images":["data:image/png;base64,"],"options":{"A":"Inverting of furrow slice","B":"Cutting through soil","C":"Pulverizing of the slice in some ploughs","D":"Enabling the plough to roll over obstacles"},"answer":"D","explanation":"The functions of part labelled I are;  - Inverting of furrow slice   - cutting through soil   - pulverizing of the slice in some plough   * Enabling the plough to roll over obstacles is not the function of mouldboard","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>7","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM MACHINERY AND IMPLEMENTS","question":"The function of the part labelled II is that it","images":["data:image/png;base64,"],"options":{"A":"makes vertical cuts","B":"makes horizontal cuts","C":"inverts the furrow slice","D":"removes mud that clings to the disc."},"answer":"B","explanation":"The function of the ploughshare is to make horizontal cuts in the soil","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>8","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : FARM SURVEYING","question":"The surveying instrument used for measuring horizontal and vertical angles is called","images":[],"options":{"A":"theodolite","B":"Gunter's chain","C":"offset staff","D":"arrow"},"answer":"A","explanation":"A theodolite is a precision instrument for measuring angles in the horizontal and vertical planes. Theodolites are mainly used for surveying applications, and have been adapted for specialized purposes in fields like metrology and rocket launch.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>9","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Crop rotation is often used in maintaining soil fertility because","images":[],"options":{"A":"all crops grown, add nutrient to the soil","B":"some of the crops fix nitrogen in the soil","C":"crops grown are ploughed into the soil","D":"the crops are rotated on different farmlands"},"answer":"B","explanation":"Crop rotation is often used in farming system in maintaining soil fertility because it fix nitrogen in the soil needed for plant growth","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>10","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FACTORS OF PRODUCTION","question":"Land is said to be fixed asset in Agriculture. This means that","images":[],"options":{"A":"its features and topography are fixed","B":"soil nutrients and its vegetative cover can be replaced","C":"its size remains fixed over time","D":"its micro organic composition is constant"},"answer":"C","explanation":"Fixed asset are asset that do not vary (i.e remain constant over a long period of time). Therefore, land is a fixed asset because its size remains fixed overtime","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>11","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : FACTORS AFFECTING LAND AVAILABILITY FOR AGRICULTURAL PURPOSE","question":"The most limiting factor affecting land availability for agriculture in urban settlements is","images":[],"options":{"A":"soil type","B":"topography","C":"climate","D":"population pressure"},"answer":"D","explanation":"Population pressure is a limiting factor affecting land availability for agriculture in urban settlements because we have more people concentrated in urban area as a result of factors such as industrialization, availability of food etc.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>12","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Rhizobium supplies nitrogen to leguminous plants by","images":[],"options":{"A":"incorporating urea into their bodies","B":"fixing atmospheric nitrogen into the soil","C":"decomposing plant and animal remains","D":"decreasing the pH value of the soil"},"answer":"B","explanation":"The presence of Rhizobium (mainly leguminous plant) supplies nitrogen to plant by fixing atmospheric nitrogen","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>13","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : ROCK FORMATION","question":"An example of igneous rock is","images":[],"options":{"A":"granite","B":"limestone","C":"coal","D":"sandstone"},"answer":"A","explanation":"Granite is an example of an igneous rock. Igneous rocks are formed from the solidification of magma or lava. Other examples of igneous rocks include basalt and obsidian. Limestone is a sedimentary rock, coal is an organic rock, and sandstone is also a sedimentary rock.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>14","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : SOIL FORMATION AND PROFILE DEVELOPMENT","question":"In chemical weathering of rocks, the equation Fe2O3 + 3H2O \u2192 Fe2O3 3H2O represents","images":[],"options":{"A":"carbonation","B":"hydration","C":"solution","D":"oxidation"},"answer":"B","explanation":"Fe2O3 + 3H2O - Fe2O3 . 3H2O represents hydration   Hydration is a chemical reaction which involves the addition of water to can chemical compound","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2016>15","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : TYPES, COMPOSITION AND PROPERTIES OF SOIL","question":"Which of the following statements is a disadvantage of decaying organic matter in soils?","images":[],"options":{"A":"Bacterial and fungal growth is enhanced","B":"minerals in organic matter are released into soil","C":"Physical conditions of soil is enhanced","D":"Water-holding capacity of soil not improved"},"answer":"A","explanation":"Advantage of decaying organic matter in soils are:  - minerals in organic matter are released into the soil   - Physical condition of the soil is enhanced   - water-holding capacity of soil is improved     The disadvantage of decaying organic matter is that it enhance bacterial and fungal growth","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>16","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"Lost of soil nutrients can be replenished by the following methods except","images":[],"options":{"A":"organic manuring","B":"fertilizer application","C":"continuous grazing","D":"cover cropping"},"answer":"C","explanation":"The method of replenishing lost soil nutrient are:  - Organic manuring - fertilizer application - cover cropping - crop rotation etc.   while continuous cropping is a farming system that causes gradual reduction in the nutrient of the soil","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>17","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : PLANT NUTRIENTS AND NUTRIENT CYCLE","question":"In the carbon cycle, carbondioxide in the air may be replenished by","images":[],"options":{"A":"respiration","B":"transpiration","C":"lightning","D":"denitrification"},"answer":"A","explanation":"Respiration is one of the process in carbon-cycle that helps to replenish carbondioxide in the air, other processes are combustion, decay fossil etc.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>18","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : IRRIGATION","question":"Irrigation can be described as the","images":[],"options":{"A":"reduction of soil water","B":"spraying of minerals on plants","C":"application of dissolved fertilizers to the soil","D":"application of water to the soil"},"answer":"D","explanation":"Irrigation is the application of controlled amounts of water to plants at needed intervals. It helps to grow agricultural crops, maintain landscapes, and revegetate disturbed soils in dry areas and during periods of less than average rainfall.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>19","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECOLOGY : DRAINAGE","question":"Which of the following conditions is a characteristic of poorly drained soil?","images":[],"options":{"A":"Presence of a large number of termites","B":"Presence of high amount of humus","C":"Decrease in the activities of microorganisms","D":"High soil fertility and productivity"},"answer":"C","explanation":"Poorly drained soils are typically characterized by a decrease in the activities of microorganisms. This is because waterlogged conditions in poorly drained soils create an anaerobic environment, which is not conducive for the survival and activity of many beneficial soil microorganisms.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>20","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"The process of removing excess maize seedlings from a stand is known as","images":[],"options":{"A":"pruning","B":"supplying","C":"thinning","D":"weeding"},"answer":"C","explanation":"Thinning is a cultural practice in agriculture which involves the removal of excess plant in other to allow spacing in plant","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>21","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ENGINEERING/MECHANIZATION : SIMPLE FARM TOOLS","question":"Study the diagram below and answer questions below      The farm tool associated with the diagram above is the","images":["data:image/png;base64,"],"options":{"A":"knife","B":"secateurs","C":"shears","D":"cutlass"},"answer":"A","explanation":"The farm tool associated with the diagram is the knife","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>22","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Study the diagram below and answer questions below    The crop associated with the diagram above is","images":["data:image/png;base64,"],"options":{"A":"Theobroma cacao","B":"Zingiber officinale","C":"Hevea brasiliensis","D":"Gossypium hirsutum"},"answer":"C","explanation":"Heavea brasiliens  is the crop associated to the diagram","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>23","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : HUSBANDRY OF SELECTED CROPS","question":"Which of the following crops requires shade at the early stage of its growth?","images":[],"options":{"A":"Plantain","B":"Banana","C":"Cocoa","D":"Sugarcane"},"answer":"C","explanation":"Cocoa requires shade at the early stage of its growth. This is because cocoa is a tropical plant that grows under the canopy of the rainforest. The shade helps to protect the young cocoa plants from direct sunlight, which can be too intense and damage the plants. Plantain, Banana, and Sugarcane can tolerate more sunlight.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>24","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"Which of the following plants is not a leguminous forage?","images":[],"options":{"A":"Centrosema pubescens","B":"Panicum maximum","C":"Stylosanthes gracilis","D":"Calopogonium mucunoides"},"answer":"B","explanation":"Centrosema pubescens ,  Stylosanthes gracilis ,  Calopogonium mucunoides are leguminous forage while  Panicum maximum is not a leguminous forage","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>25","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"The process of crossing two pure lines of plants of the same species is called","images":[],"options":{"A":"selection","B":"genotype improvement","C":"hybridization","D":"inbreeding"},"answer":"D","explanation":"In breeding process of crossing two pure lines of plants/animal of the same species","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>26","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : CROP IMPROVEMENT","question":"Pure lines of crops are produced through continuous","images":[],"options":{"A":"selection","B":"hybridization","C":"cross breeding","D":"inbreeding"},"answer":"D","explanation":"Continuous inbreeding enhances pure lines of crops/animal (i.e it helps for continuous existence of the desired characteristics)","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>27","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"Quarantine regulations are established so as to","images":[],"options":{"A":"allow the importation of diseased plant and animal materials","B":"prevent the introduction of foreign diseases into the country","C":"assist farmers to grow foreign crops","D":"facilitate the rapid spread of foreign diseases"},"answer":"B","explanation":"Quarantine regulations are established so as to prevent the introduction of foreign disease into a country","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>28","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PROTECTION : DISEASES OF CROPS","question":"The most effective method of controlling viral diseases in crops is by","images":[],"options":{"A":"spraying with Bordeaux mixture","B":"removing and burning affected crops","C":"practicing crop rotation","D":"planting at recommended spacing"},"answer":"B","explanation":"The removal and burning of plant affected with viral disease is the most effective method of controlling the viral diseases","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>29","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PROTECTION : PESTS OF CROPS","question":"Which of the following insects transmits swollen shoot virus of Cocoa?","images":[],"options":{"A":"Stem borer","B":"Mealybug","C":"White fly","D":"Capsid"},"answer":"B","explanation":"The Mealybug is the insect that transmits the swollen shoot virus of Cocoa. The virus is a serious disease of cocoa in West Africa. The mealybug transmits the virus from infected to healthy plants. The disease causes swelling of the shoots and can lead to death of the plant if not controlled.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>30","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PROTECTION : WEEDS","question":"The use of parasites and predators to control weeds is referred to as","images":[],"options":{"A":"biological control","B":"chemical control","C":"cultural control","D":"mechanical control"},"answer":"A","explanation":"The use of parasites and predators to control weeds is referred to as biological control. Biological control is a method of controlling pests (including insects, mites, weeds and plant diseases) using other living organisms. It relies on predation, parasitism, herbivory, or other natural mechanisms, but typically also involves an active human management role.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>31","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"Forest resources can be managed by the following measures except","images":[],"options":{"A":"taungya farming","B":"selective exploitation","C":"promoting deforestation","D":"preventing bush burning"},"answer":"C","explanation":"Measure of managing forest resources are;  - Taungy of farming - selective exploitation - prevent bush burning   * Promoting deforestation is not a measure of forest resources","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>32","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"FORESTRY : FOREST MANAGEMENT","question":"The continuous removal of forest trees without replacement is known as","images":[],"options":{"A":"afforestation","B":"taungya farming","C":"deforestation","D":"selective exploitation"},"answer":"C","explanation":"The continuous removal of forest trees without replacement is known as deforestation. Afforestation is the process of establishing a forest, or stand of trees, in an area where there was no forest. Taungya farming is a type of agroforestry practice where annual crops are grown in the understory of a forest until the canopy closes. Selective exploitation involves the removal of specific trees while leaving the majority of the forest intact.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>33","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANATOMY AND PHYSIOLOGY OF FARM ANIMALS","question":"A farm animal which possesses a pair of caeca is","images":[],"options":{"A":"pig","B":"fowl","C":"sheep","D":"cattle"},"answer":"B","explanation":"A farm animal which possesses a pair of caeca is a fowl. The caeca are a pair of blind pouches located where the small and large intestines meet. They host a large number of bacteria which help in the digestion of food. Pigs, sheep, and cattle do not have a pair of caeca.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>34","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"Oestrogen in female animals is not responsible for","images":[],"options":{"A":"development of secondary sexual characteristics","B":"onset of heat period","C":"milk let-down after parturition","D":"development of udder"},"answer":"C","explanation":"Oestrogen in female animals is responsible for   - Development of secondary sexual characteristics   - Onset of heat period   - Development of udder     Progestrone is responsible for milk let-down after parturition","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>35","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"A beef cow gained 75kg over a period of two months and two-days. What is its average weight gain?","images":[],"options":{"A":"0.83 kg","B":"1.21 kg","C":"1.28 kg","D":"2.25 kg"},"answer":"B","explanation":"Parameters given:   Weight = 75kg  Number of days = 62 days.(2 months and 2 days)  Average weight gain = 75/62 = 1.21kg","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>36","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL REPRODUCTION","question":"A disadvantage of natural incubation is that","images":[],"options":{"A":"the eggs cannot be candled","B":"the chicks are less healthy","C":"the brooding hens sometimes abandon eggs","D":"it takes a longer time for eggs to hatch"},"answer":"C","explanation":"Natural incubation has several disadvantages, one of which is that the brooding hens sometimes abandon eggs. This can lead to the eggs not being incubated properly, which can result in the eggs not hatching. The other options are not disadvantages of natural incubation. For example, it is possible to candle eggs during natural incubation, and the health of the chicks and the time it takes for eggs to hatch are not affected by the method of incubation.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>37","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL NUTRITION","question":"Ruminants fed on dried grasses are given feed supplements to","images":[],"options":{"A":"increase water intake","B":"provided bulk to feed","C":"reduce microbial activity","D":"provide deficient nutrients"},"answer":"D","explanation":"Ruminants are fed on dried grasses, which are often deficient in certain nutrients. Feed supplements are given to provide these deficient nutrients. This is important for the overall health and productivity of the ruminants.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>38","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Which of the following animal diseases is not associated with malnutrition?","images":[],"options":{"A":"Aspergillosis","B":"Acidosis","C":"Milk fever","D":"Rickets"},"answer":"A","explanation":"Acidosis, milk fever, Ricket are animal diseases associated with nutrient   Aspergillosis is a disease caused by fungi","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>39","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"CROP PRODUCTION : PASTURE AND FORAGE CROPS","question":"The botanical name of Northern gamba grass is","images":[],"options":{"A":"Cynodon dactylon","B":"Panicum maximum","C":"Pennisetum purpureum","D":"Andropogon gayanus"},"answer":"D","explanation":"The botanical name for Northern gamba grass is  Andropogon gayanus . Botanical names are the scientific names given to plants and are universally accepted and used in scientific literature.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>40","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : LIVESTOCK MANAGEMENT","question":"The cut and carry system of feeding livestock is termed","images":[],"options":{"A":"rotational grazing","B":"zero grazing","C":"mixed grazing","D":"controlled grazing"},"answer":"B","explanation":"Zerograzing also called cut and carry system of feeding livestock. It is the grazing where the feed are given to the animals in their pen","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>41","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL IMPROVEMENT","question":"Progeny selection involves selection of breeding stock on the basis of","images":[],"options":{"A":"feed conversion efficiency of the parents","B":"merits of each animal","C":"merits of the dam only","D":"performance of offspring"},"answer":"D","explanation":"Progeny selection involves selection of breeding stock on the basis of the performance of offspring","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>42","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"The cattle disease which is likely to be most common in the forest belt of West Africa is","images":[],"options":{"A":"foot and mouth","B":"trypanosomiasis","C":"anthrax","D":"tuberculosis"},"answer":"B","explanation":"The cattle disease which is likely to be most common in the forest belt of West Africa is 'trypanosomiasis'. Trypanosomiasis, also known as sleeping sickness in humans and nagana in animals, is a parasitic disease transmitted by the tsetse fly, which is common in the forest belt of West Africa.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>43","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : ANIMAL HEALTH MANAGEMENT","question":"Ecto-parasites can be controlled by","images":[],"options":{"A":"administering antibodies to host","B":"administering antibiotics to host","C":"dipping of host","D":"deworming of host"},"answer":"C","explanation":"Ecto-parasites are parasites that live on the exterior of an animal. They can be controlled by dipping the host in a solution that kills the parasites. This method is often used in livestock management where animals are dipped in a pesticide solution to kill ticks and other ecto-parasites. Administering antibodies or antibiotics to the host would not directly affect ecto-parasites as they live outside the host's body. Deworming is used to control endo-parasites (parasites living inside the host's body), not ecto-parasites.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>44","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Cropping in fish farming is the act of","images":[],"options":{"A":"stocking fish","B":"processing fish","C":"harvesting fish","D":"feeding fish"},"answer":"C","explanation":"In fish farming, cropping refers to the act of harvesting fish. It involves the removal of mature fish from the pond for consumption or sale. Stocking fish refers to the introduction of young fish into the pond, processing fish involves preparing the fish for consumption or sale, and feeding fish is the act of providing food for the fish.","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>45","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"ANIMAL PRODUCTION : AQUACULTURE","question":"Methods of preserving fish include the following except","images":[],"options":{"A":"drying","B":"smoking","C":"salting","D":"soaking"},"answer":"D","explanation":"Drying, smoking, salting are methods of preserving fish.  Soaking is not a method of preserving food","marks":"1","difficulty":"1"},{"id":"objective>Agricultural Science>2016>46","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : PRINCIPLES OF DEMAND","question":"Determine the price elasticity of demand if the price of yam tuber rises by 10% (0.1) and the quantity demanded falls by 5% (0.05)","images":[],"options":{"A":"0.5","B":"0.4","C":"0.3","D":"0.1"},"answer":"A","explanation":"The price elasticity of demand is calculated by the percentage change in quantity demanded divided by the percentage change in price. In this case, it would be -0.05/0.1 = -0.5. However, the elasticity of demand is usually expressed in absolute terms, so the answer would be 0.5.","marks":"1","difficulty":"3"},{"id":"objective>Agricultural Science>2016>47","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : FARM MANAGER","question":"Most farm businesses fail because of","images":[],"options":{"A":"death of the manager","B":"lack of capital","C":"labour problems","D":"poor management"},"answer":"D","explanation":"The most common reason for the failure of farm businesses is poor management. This includes poor financial management, lack of planning, and not keeping up with market trends.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>48","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : MARKETING OF AGRICULTURAL PRODUCE","question":"Which of the following activities is not marketing function?","images":[],"options":{"A":"Buying of agricultural commodities","B":"planting of crops","C":"Transportation of farm produce","D":"Storage of farm produce"},"answer":"B","explanation":"The following activities are function of marketing;  - Buying of agricultural commodities   - Transporting of farm produce   - Storage of farm produce     Planting of crops is the function of the farmer","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>49","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL INSURANCE","question":"Risk on commercial farms could result from","images":[],"options":{"A":"price stability","B":"crop failure","C":"insurance","D":"diversification"},"answer":"B","explanation":"Commercial farming involves the cultivation of crops for sale. It is a high-risk venture because it is heavily dependent on the weather. Crop failure, which could be due to unfavorable weather conditions, pests, or disease, is a significant risk in commercial farming. Therefore, the correct answer is 'crop failure'. Price stability, insurance, and diversification are strategies to manage or mitigate risk, not sources of risk.","marks":"1","difficulty":"2"},{"id":"objective>Agricultural Science>2016>50","subject":"Agricultural Science","year":"2016","type":"Objective","topic":"AGRICULTURAL ECONOMICS AND EXTENSION : AGRICULTURAL EXTENSION","question":"An agricultural extension officer should be able to","images":[],"options":{"A":"create new jobs for farmers","B":"raise funds for farmers","C":"cultivate a large farm","D":"guide and educate farmers"},"answer":"D","explanation":"An agricultural extension officer's primary role is to provide expert advice and information to farmers to improve their farming practices. This includes guiding and educating farmers on the best farming techniques, crop varieties, pest control methods, and other aspects of farming. Therefore, the correct answer is 'guide and educate farmers'. Creating new jobs for farmers, raising funds for farmers, and cultivating a large farm are not typically responsibilities of an agricultural extension officer.","marks":"1","difficulty":"2"}];